@import url('https://fonts.googleapis.com/css2?family=Cairo:wght@400;500;600;700&display=swap');

/* ── Base ── */
* {
    font-family: 'Cairo', sans-serif;
    box-sizing: border-box;
}

body {
    font-weight: 500;
    color: #2f3b52;
    background: #ffffff;
    line-height: 1.6;
}

p, div, td, li, span {
    font-weight: 500;
    color: #2f3b52;
}

/* ── Headings — neutral dark palette ── */
h1 {
    font-weight: 700;
    color: #1a2640;
    font-size: 22px;
    border-bottom: 2px solid #e0e6ed;
    padding-bottom: 6px;
    margin-bottom: 12px;
}

h2 {
    font-weight: 700;
    color: #1a2640;
    font-size: 18px;
}

h3 {
    font-weight: 600;
    color: #2f3b52;
    font-size: 15px;
}

h4, h5, h6 {
    font-weight: 600;
    color: #4a5a70;
}

/* ── Labels ── */
label {
    font-weight: 600;
    color: #2f3b52;
    background-color: #f0f4f8;
    padding: 2px 7px;
    border-radius: 4px;
    display: inline-block;
    border: 1px solid #dce3ea;
    font-size: 12px;
}

/* ── Tables ── */
table {
    width: 100%;
    border-collapse: collapse;
}

th {
    background-color: #f0f4f8;
    color: #1a2640;
    font-weight: 700;
    padding: 8px 10px;
    border: 1px solid #dce3ea;
    text-align: right;
}

td {
    padding: 7px 10px;
    border: 1px solid #e6eaef;
    color: #2f3b52;
    font-weight: 500;
}

tr:nth-child(even) td {
    background-color: #f8fafc;
}

/* ── RTL / LTR support ── */
.rtl {
    direction: rtl;
    text-align: right;
}

.ltr {
    direction: ltr;
    text-align: left;
}

/* ── Print helpers ── */
@media print {
    body {
        font-size: 12px;
    }
    h1 { font-size: 18px; }
    h2 { font-size: 15px; }
    h3 { font-size: 13px; }
}
